from collections import deque

def is_bipartite(n, adj):
    """
    n   : number of vertices
    adj : adjacency list dict {u: [v, ...]}
    Returns True if the graph is bipartite, False otherwise.
    """
    color = [-1] * n

    for start in range(n):
        if color[start] != -1:
            continue
        color[start] = 0
        queue = deque([start])
        while queue:
            u = queue.popleft()
            for v in adj.get(u, []):
                if color[v] == -1:
                    color[v] = ___________   # assign opposite colour
                    queue.append(v)
                elif color[v] == color[u]:   # same colour — odd cycle
                    return False
    return True
